const ID_REPLIED = "Label_2354037965168050234"; 
const ID_WAITING = "Label_4132664344787187736";
const ID_N8N = "Label_5515322872405991067";
const ID_NEED_REPLY = "Label_7465406405412998085";
const ID_FROM_RECRUITER = "Label_7667780014404298288";

const MY_EMAIL = "odeliya.charitonova.dev@gmail.com";
const allJobLabels = [ID_REPLIED, ID_WAITING, ID_N8N, ID_NEED_REPLY, ID_FROM_RECRUITER];

// ⏱️ TESTING: 1 minute. 
// 🔁 PRODUCTION: replace with 12 * 60 * 60 * 1000
const TIME_LIMIT = 12 * 60 * 60 * 1000;

const extractEmail = (str) => {
    if (!str) return "";
    const match = str.match(/<(.+?)>/) || [null, str];
    return match[1].trim().toLowerCase();
};

const classifyMessage = (item) => {
    const now = Date.now();
    const internalDate = parseInt(item.internalDate || now);
    const snippet = (item.snippet || "").toLowerCase();
    const subject = (item.Subject || "").toLowerCase();
    const labelIds = (item.labels || []).map(l => l.id);

    const fromEmail = extractEmail(item.From);
    const toEmail = extractEmail(item.To);

    const subjectIsReply = subject.startsWith("re:");
    // For outgoing emails, we only trust the subject prefix to detect replies.
    // threadHasJobLabel would always be true for recruiter threads (tagged FROM_RECRUITER),
    // which would incorrectly classify first outreach as REPLIED.
    const isReply = subjectIsReply;

    if (fromEmail === MY_EMAIL && toEmail === MY_EMAIL) {
        return { label: ID_N8N, date: internalDate };
    }

    if (fromEmail === MY_EMAIL) {
        return { 
            label: isReply ? ID_REPLIED : ID_WAITING, 
            date: internalDate 
        };
    }

    // Incoming email
    const isRecruiter = 
        fromEmail.includes("recruiter") || 
        snippet.includes("interview") || 
        subject.includes("position") || 
        snippet.includes("applied");

    if ((now - internalDate) > TIME_LIMIT) {
        return { label: ID_NEED_REPLY, date: internalDate };
    } else {
        return { label: ID_FROM_RECRUITER, date: internalDate };
    }
};

// KEY FIX: group all messages by threadId, then for each thread
// keep only the classification of the LATEST message.
// This prevents multiple messages in the same thread from producing
// conflicting labels - the most recent message reflects current state.
const allItems = $input.all();
const threadMap = {};

for (const inputItem of allItems) {
    const item = inputItem.json;
    const threadId = item.threadId;
    const result = classifyMessage(item);

    // If we've seen this thread before, only replace if this message is newer
    if (!threadMap[threadId] || result.date > threadMap[threadId].date) {
        threadMap[threadId] = {
            threadId,
            labelIdToAdd: result.label,
            labelsToClear: allJobLabels,
            date: result.date
        };
    }
}

// Return one item per thread (not one per message)
return Object.values(threadMap).map(t => ({
    threadId: t.threadId,
    labelIdToAdd: t.labelIdToAdd,
    labelsToClear: t.labelsToClear
}));
